    def get_dua(self, key: str) -> Optional[Dict]:
        """取得特定咒語"""
        return self.DUAS.get(key)

    def list_all(self) -> List[str]:
        return list(self.DUAS.keys())

    def print_dua(self, key: str):
        """美觀顯示咒語"""
        dua = self.get_dua(key)
        if not dua:
            print("找不到該咒語")
            return
        print(f"\n=== {dua['name']} ===")
        print(f"章節：{dua['chapter']}")
        print(f"阿拉伯文：{dua['arabic'][:120]}...（完整版可繼續擴充）")
        print(f"翻譯：{dua['translation']}")
        print(f"用途：{dua['use']}")
        print(f"使用條件：{dua['condition']}")
        if dua.get("with_wafq"):
            print("✅ 可與 wafq 方陣配合使用")
